import{$ as e,A as t,B as n,V as r}from"./chunks/framework.6NwDR3kH.js";var i=JSON.parse(`{"title":"相机翻拍平场校正客串扫描仪","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/色彩管理/相机当扫描仪.md","filePath":"ccc/色彩管理/相机当扫描仪.md"}`),a={name:`ccc/色彩管理/相机当扫描仪.md`};function o(t,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[r(`<h1 id="相机翻拍平场校正客串扫描仪" tabindex="-1">相机翻拍平场校正客串扫描仪 <a class="header-anchor" href="#相机翻拍平场校正客串扫描仪" aria-label="Permalink to “相机翻拍平场校正客串扫描仪”">​</a></h1><p>本文着重于相机客串扫描仪，校色打印机流程还是参考：</p><ul><li><a href="https://www.bilibili.com/video/BV1gFSCYqE5w" target="_blank" rel="noreferrer">无色卡-扫描仪校色打印机视频</a>；<a href="https://zhuanlan.zhihu.com/p/441885301" target="_blank" rel="noreferrer">文章</a>；相机客串扫描仪的操作视频制作中。</li><li><a href="https://www.bilibili.com/video/BV1gFSCYqE5w" target="_blank" rel="noreferrer">无色卡-扫描仪校色打印机视频</a>；<a href="https://zhuanlan.zhihu.com/p/441885301" target="_blank" rel="noreferrer">文章</a>；相机客串扫描仪的操作视频制作中。</li><li><a href="https://pan.baidu.com/s/1zSW2UQ2NfF16cG7zuKrDvg?pwd=bxzz" target="_blank" rel="noreferrer">网盘</a>；<a href="https://pan.baidu.com/s/1zSW2UQ2NfF16cG7zuKrDvg?pwd=bxzz" target="_blank" rel="noreferrer">网盘</a>；<a href="https://pan.baidu.com/s/1zSW2UQ2NfF16cG7zuKrDvg?pwd=bxzz" target="_blank" rel="noreferrer">网盘</a>；</li><li></li><li><a href="https://docs.qq.com/aio/DZmdiQkdGR1BkT3FQ?p=BvrSuXhVTOigks70P9nRRM" target="_blank" rel="noreferrer">我制作的类IT8反射色卡详见。</a></li></ul><p><a href="https://zhuanlan.zhihu.com/p/594218037" target="_blank" rel="noreferrer">打印机（墨水系统梗概与兼容墨水取舍）</a>；<a href="https://zhuanlan.zhihu.com/p/622264483" target="_blank" rel="noreferrer">分光光度计校色仪介绍</a>；</p><p>手机相机翻拍校色打印机，<strong>有啥用啥，都很随便</strong>，文中的介绍侧重优选，实际上都是无所谓的，<strong>有啥用啥。</strong></p><p><a href="https://zhuanlan.zhihu.com/p/678972325" target="_blank" rel="noreferrer">生成通用相机校色DCP配置文件参考该文，丙烯色卡研究中，喷笔+丙烯颜料绘制，仿爱色丽24色卡。</a></p><h2 id="it8反射色卡用于相机校色" tabindex="-1">IT8反射色卡用于相机校色 <a class="header-anchor" href="#it8反射色卡用于相机校色" aria-label="Permalink to “IT8反射色卡用于相机校色”">​</a></h2><p>固定相同光源，平场校正后配合色卡生成基于3Dlut的icc，客串扫描仪实测完全可行。老外也有用IT8色卡校色后艺术品复制的实践案例。</p><p><strong>生成通用相机校色DCP配置文件可能受同色异谱干扰</strong></p><p>通常相机的RAW流程中亮度由曝光或类影调曲线功能调整，校色配置文件是2.5Dlut，只调整饱和度和色度（色相），就是HSL的H和S。而3Dlut会校正亮度，不具有通用性。因此爱色丽SG色卡不过96个有效色块。</p><p>通用DCP配置文件（2.5Dlut，不处理亮度），至少需要两套光源打光来适配白平衡插值算法，折腾可以用卤素灯泡作为A光源，首尔sunlike的LED灯珠6500K灯泡作为D65光源，不过光谱还不是最完美。</p><p>银盐相纸是CMY三层染料连续调，而常用于相机校色的爱色丽24、SG色卡是连续颜料层，而不是通过CMY混合实现，有潜在的同色异谱可能性。<strong>我推测“原生颜料”可能相对更接近自然颜色。</strong></p><p>CCD的主要噪声是读出噪声，色块的纯净度、均匀度相对较高，可以接受较小的色块，而相机的场景中通常为了打光均匀，光源和相机都离得老远，同时CMOS主要的光子散粒噪声拍摄色块不够纯净，银盐色卡色块太小反而扯后腿，一堆色块反而可能叠加系统误差。</p><p>分光光度计使用的光路是45°/0°，扫描仪也是类似的光路。即光度计垂直于平面接收反射光，而光源同平面呈45度。假设平面是绝对光滑的平面，则光度计不会接收到镜面反射光，只接收到漫反射光。相机要调整避免炫光。</p><h3 id="扫描仪vs相机" tabindex="-1">扫描仪VS相机 <a class="header-anchor" href="#扫描仪vs相机" aria-label="Permalink to “扫描仪VS相机”">​</a></h3><p>相机上限更高，不过<a href="https://zhuanlan.zhihu.com/p/438756840" target="_blank" rel="noreferrer">二手CCD扫描仪如V330、V370基本才200块</a>左右。</p><p><strong>CIS设计目的就是降低成本，表现通常甚至还不如CCD扫描仪。</strong>由于每列一个读出通道导入固定模式噪声（FPN），使得CIS扫描图往往出现干涉条纹（摩尔纹），非常显眼。CCD和CMOS受到的主要噪声在CIS上全有，又没有相机CMOS强大的ISP降噪能力，可以说是烂上加烂。</p><p>CCD扫描仪的暗电流+读出噪声导致其在暗部有明显的结构性噪声，既暗部色块很脏，损失阴影层次，多次扫描的暗部RGB值由于温漂会变化，甚至差值能达到10左右（RGB255伽马2.2），这直接导致用IT8色卡进行校色不易校准暗部。</p><p><strong>不过CCD扫描仪便宜且开箱即用</strong>，正常扫描，一坨黑有点偏色人眼难以感知，只有用于复制或校色打印机，这样对色准有要求的场景，暗部偏脏的短板已经较难接受。</p><p>据我实际测试，校色打印机，连小米12S手机相机（IMX707）的效果都比CCD扫描仪好。仅仅从标称的读出噪声来看，相机CMOS的读出噪声并没有显著低于CCD，我推测可能是ISP降噪的作用。</p><p>CMOS主要噪声来源有模式噪声，是CIS扫描仪干涉条纹的主要来源，但现代CMOS似乎已明显改善。此外还有光子散粒噪声，导致拜尔阵列在色彩插值（去马赛克，拜尔阵列解码）后产生噪点，且可能引入插值误差或伪色。不过微单相机+像素位移功能显著改善。</p><p>如图所示：左CCD扫描仪，右手机相机翻拍，相机翻拍明显更中性，CCD扫描仪均匀度更高但暗部漂移有点脏，不易解决。而手机相机的短板更换微单相机+像素位移功能就可以解决。</p><blockquote><p>尝试黑帧扣除，既扫描时附纯黑色条，减去纯黑色条的RGB值，由于不是绝对黑体，像是有信息损失，而且扫描仪CCD的暗部噪声同信息之间似乎并非是简单的线性关系，在L十几的亮度之后暗部色块脏的现象会莫名改善。 我推测可能应该把CCD隔出一小段遮光，接触不到光线，用来黑帧扣除，或光源不亮拍一帧作为黑帧，但是感觉这应该很好实现，不排除厂家本来就已经做了黑帧扣除。</p></blockquote><p>爱普生V850pro旗舰扫描仪，CCD疑似索尼ILX185K，2006年就发布了，无疑量子效率已经落后于新时代的CMOS。而相机CMOS一直在迭代，还可以向右曝光提升信噪比。</p><h2 id="相机翻拍布置" tabindex="-1"><strong>相机翻拍布置</strong> <a class="header-anchor" href="#相机翻拍布置" aria-label="Permalink to “相机翻拍布置”">​</a></h2><h3 id="必须弄平" tabindex="-1"><strong>必须弄平</strong> <a class="header-anchor" href="#必须弄平" aria-label="Permalink to “必须弄平”">​</a></h3><p>如果不是大量的翻拍扫描，用美纹纸胶带贴在边上贴平就行。<a href="https://docs.qq.com/aio/DZmdiQkdGR1BkT3FQ" target="_blank" rel="noreferrer">我的类IT8反射色卡</a>会赠送A4大小双面胶，也可以自行贴在平整硬板上，如亚克力板。</p><p>软件对色块的识别允许有平面上的歪斜，甚至透视上的梯形形变用透视裁切也能弄直，但翘曲不能正确定位色块位置。平面和曲面受到的光照不一致，平场校正后可能产生误差。翘曲也可能导致轻微的炫光。</p><p><strong>玻璃</strong>最好是双面镀膜ar减反射玻璃，普通超白玻璃俯拍会有明显倒影，除非斜着拍，再透视裁切。</p><p>据我<a href="https://zhuanlan.zhihu.com/p/2024816421058659467" target="_blank" rel="noreferrer">测试</a>，ar减反射玻璃挑便宜的买就行，追求性能考虑淘宝优视玻璃科技（蓝膜）、淘宝光玻清影（绿膜）（透影科技）、淘宝桐宇玻璃（绿膜）。</p><p>淘宝滟彩艺术唯一标称提供UV99阻隔ar减反射玻璃，<strong>如果用阳光作为光源校色打印机，必须阻隔UV</strong>，不然阳光中UV成分太足，相纸基本都含荧光增白剂，激发程度太夸张。或者可能可以配合UV阻隔膜。</p><p>如果要用玻璃压平，打印一张A4的黑纸，用玻璃压平，观察是否有炫光或倒影，要尽量调整摆放来避免炫光和倒影。</p><h3 id="光源有啥用啥" tabindex="-1">光源有啥用啥 <a class="header-anchor" href="#光源有啥用啥" aria-label="Permalink to “光源有啥用啥”">​</a></h3><p><strong>尽量打光均匀，但必须调整摆放避免炫光、影子</strong></p><p>由于会做平场校正，所以单台台灯打光也可以，但最好俩光源起步。</p><blockquote><p>台灯、类似于优蓝子VL49的小补光灯、甚至吸顶灯，都可以，是个灯就行。</p></blockquote><p>阳光中UV成分太足，相纸基本都含荧光增白剂，激发程度太夸张。要么用UV99阻隔玻璃，或者可能可以配合UV阻隔膜。或者用人造光源就好了。</p><p>如果无色卡蹭Adobe Camera RAW（后文简称<strong>ACR</strong>）的DCP配置文件，一般基于A光源+D65光源内插适配白平衡算法，配合6500K色温光源误差可能相对小一点点。</p><p>如果要买光源，优选首尔SunLike灯珠。可以买SunLike灯珠做的灯条模组，再买个220V开关线，接上就行。淘宝光美科技就有，不过他卖的模组没有贴好漫反射透镜，要自己另外买散热胶水，把漫反射透镜粘上去。</p><blockquote><p>台灯、吸顶灯避免SunLike灯珠，其使用紫光激发荧光粉，友商通常是双波长蓝光激发荧光粉。这些灯泡老化后，往往紫光或双波长蓝光可能泄露，无疑紫光危害更大。</p></blockquote><p>技术原理并不复杂，无非就是调整荧光粉配方。显色指数已经烂大街，实际意义已经非常有限，具体还是关注实测光谱，主要关注480nm左右的青色不要明显凹陷。</p><blockquote><p>通常印刷看样光源用5000K色温光源，Adobe流程的ProPhoto也是D50白点，IT8色卡的色值文件默认D50白点。6500K看样光源下纸白相对屏幕显示的6500K要蓝一点，看样光源5000K，屏幕白点6500K，两者的白点观感相对更接近。 配合6500K光源，如果数码冲洗软件内部是D50白点，经过白平衡校准就已经是D50白点，配合D50色值即可。 或采用D65白点的闭环流程，我制作的IT8反射色卡既提供光谱反射率也提供D65色值。</p></blockquote><h3 id="俯拍架" tabindex="-1">俯拍架 <a class="header-anchor" href="#俯拍架" aria-label="Permalink to “俯拍架”">​</a></h3><p>手持摄影利用PS透视裁切工具裁切到当白场图用的普通纸对齐也可以。</p><p>最好有俯拍架，平场校正的可靠性更高，还省了透视裁切的操作。手机十几块买一个就行，考虑力臂支架，呈&lt;字型，高度长度调节范围受限，但调起来舒服一点点。其他结构便宜的非常难用还不稳定。</p><p>折腾可以试试可调显示器支架+VESA转云台螺丝，可以配延长杆+云台手机夹，也可以配相机云台。</p><p>相机就比较贵了，手头有三脚架的考虑只加装一根横杆，不过要加配重。</p><p>三脚架+横杆，优选4KG以上重型三脚架，少说也要几百块，非常笨重，还占地方。</p><h3 id="光路布置" tabindex="-1">光路布置 <a class="header-anchor" href="#光路布置" aria-label="Permalink to “光路布置”">​</a></h3><p>优选左右各一个光源，位置约45度左右，有条件光源尽量远一点。既光源距离翻拍件的高度与长度大概差不多，光源尽量高于相机。</p><blockquote><p>如果配合ar减反射玻璃，浅色手机或手机壳受到光照的部分往往会成像，可以买吸光海绵贴在两边，或专门买个手机壳用来贴吸光海绵。</p></blockquote><h3 id="相机-镜头" tabindex="-1"><strong>相机+镜头</strong> <a class="header-anchor" href="#相机-镜头" aria-label="Permalink to “相机+镜头”">​</a></h3><p>校色打印机手机相机就足够。</p><p>相机优选支持像素位移pixel shift功能（抖抖乐摇摇乐）的型号。<a href="https://learnandsupport.getolympus.com/learn-center/photography-tips/browse-tips-by-camera-feature/high-res-shot-mode" target="_blank" rel="noreferrer">奥之心</a>、<a href="https://www.nikonimgsupport.com/eu/BV_article?articleNo=000066759&amp;configured=1&amp;lang=en_GB" target="_blank" rel="noreferrer">尼康</a>对像素位移的介绍，主要还是看哪些设备支持。<a href="https://www.dpreview.com/reviews/image-comparison" target="_blank" rel="noreferrer">DPREVIEW的样张</a>，大部分支持像素位移的机型一般可选Px Shift样张。</p><p>M43，奥之心E-M5 Mark III（IMX270），尼康55mm F2.8 AIS尼康单反F卡口微距镜头+转接环。该镜头三四百块就能买到。机身也可以考虑松下G9（IMX272）。</p><p>相同技术水平的CMOS，M43相对全幅，没有本质差异。全幅的优势在于，镜头大，更容易做好。但全幅有IMX410这样的甜品CMOS，搭载IMX410的松下S5全幅机身相对M43机身贵不了多少。而M43要么是十年老兵IMX270/272；要么是奥之心OM1的IMX472，技术上比IMX410好，但贵的一逼。</p><p>全幅，也考虑尼康55微转接，或随便弄个镜头客串，只要镜头有Lcp矫正配置文件就行，画面四周最好裁切掉一部分不用。<a href="https://helpx.adobe.com/camera-raw/digital-negative.html#Adobe_Lens_Profile_Creator" target="_blank" rel="noreferrer">DIY Adobe LCP</a></p><blockquote><p>大模型说可以用APO Rodagon-D 75mm f/4.5、Rodenstock Rodagon 80mm f/4、Componon-S 等放大机镜头转接。</p></blockquote><h2 id="平场校正flat-field" tabindex="-1"><strong>平场校正Flat-field：</strong> <a class="header-anchor" href="#平场校正flat-field" aria-label="Permalink to “平场校正Flat-field：”">​</a></h2><p>拍摄RAW（DNG），用不反光的白纸（如一沓普通纸）拍摄“白场图”做平场校正，翻拍件放在充当白场图的白纸上拍摄，<strong>优选俯拍架，</strong>否则利用透视裁切工具裁切到当白场用的普通纸并对齐。</p><p>白场图和翻拍图都不要过曝。如果平场校正是用PS或darktable混成做的，<strong>必须控制白场图更亮</strong>。比如拍白场+2~3档ev，拍色靶不加。如果不知道怎么操作实现，就默认自动测光，在冲洗软件里给白场图+曝光吧。</p><p>平场校正<strong>优选基于RAW数据</strong>，即线性且没有应用色调曲线的数据，这样校正后相对更均匀。后文【手机相机拍摄RAW】一节介绍了部分手机如何拍RAW。</p><p>数码冲洗后，白场图层高于原图，白场图层混合模式用划分即可。平场校正的原理就是如此朴实无华。<strong>如果没有俯拍架，</strong>数码冲洗后用PS透视裁切对齐客串白场的白纸。</p><p>会这一招就够了，可以直接跳转下一章节【无色卡蹭DCP配置文件】。</p><blockquote><p>通常JPG直出处理过影调，ACR冲洗默认会加载DCP配置文件中的色调曲线，不是线性数据。不如线性数据均匀。</p></blockquote><p>最好配合俯拍架：</p><p>darktable，禁用S形函数，启用混成，把白场图拖到混成里，混合模板启用均匀，模式相除。主要用于冲洗后配合IT8色卡。（支持没俯拍架透视裁切过的图片，但感觉不如冲洗后用PS了）</p><p>Capture One（简称C1）选中白场图，应用项-建立LCC平场校正，选中白场图和翻拍图，应用项-应用LCC平场校正。既可以保存为TIF也可以保存为DNG，再用ACR冲洗。</p><p>C1和ACR支持深度学习AI降噪（去杂色）功能，如果用于翻拍扫描效果可能相对好一点。</p><p>RawTherape，（修改版ART-AnotherRawTherape）RAW选项卡，平场校正。可以加载ACR的DCP配置文件，且不加载色调曲线，用于无色卡校色打印机。</p><p>Lightroom Classic要把白场图放在一组图片的第一张或最后一张，要软件识别出是白场图，但不清楚具体要什么样的图才行，我试了几次LR都不认&quot;白场图&quot;。</p><h3 id="有色卡" tabindex="-1">有色卡 <a class="header-anchor" href="#有色卡" aria-label="Permalink to “有色卡”">​</a></h3><p>有色卡，数码冲洗后做平场校正，之后导出.tif图片，<a href="https://www.bilibili.com/video/BV1pZEZzeEAY" target="_blank" rel="noreferrer">参考视频生成icc</a>；<a href="https://www.bilibili.com/video/BV1poEZzNESX" target="_blank" rel="noreferrer">参考视频批量使用icc转换；</a></p><p>配合色卡优先用darktable软件，darktable的颜色校准控件是用CAT16进行色度适应转换，色准比简单的点白平衡更高。</p><p><strong>相机私有格式</strong></p><p>尝试用<a href="https://helpx.adobe.com/camera-raw/using/adobe-dng-converter.html" target="_blank" rel="noreferrer">Adobe DNG Converter</a>转换为.DNG</p><h3 id="无色卡蹭dcp配置文件" tabindex="-1"><strong>无色卡</strong>蹭DCP配置文件 <a class="header-anchor" href="#无色卡蹭dcp配置文件" aria-label="Permalink to “无色卡蹭DCP配置文件”">​</a></h3><p>优选搭配IT8反射色卡，<a href="https://docs.qq.com/aio/DZmdiQkdGR1BkT3FQ?p=BvrSuXhVTOigks70P9nRRM" target="_blank" rel="noreferrer">请：色卡文档。</a></p><p>看是否有<a href="https://helpx.adobe.com/cn/camera-raw/kb/camera-raw-plug-supported-cameras.html" target="_blank" rel="noreferrer">Adobe Camera Raw支持</a>，<a href="https://helpx.adobe.com/hk_zh/camera-raw/kb/camera-raw-plug-in-installer.html" target="_blank" rel="noreferrer">ACR官方下载</a>，学习版PS也可以直接装官网的最新版ACR。</p><blockquote><p>手机相机一般支持苹果三棒、徕卡标小米、哈苏标OPPO。某家给白皮猪上供都上不对路，标白贴，还是当路边。</p></blockquote><p>如果没有被ACR支持，拍jpg直出自行测试，但由于各家的jpg直出基本都是严重的风格化偏色，正常流程通常不具有实用性。针对jpg直出，优先考虑后文的【JPG直出变通方法】。</p><p><strong>尽量有ACR支持，蹭DCP配置文件：</strong></p><p>蹭DCP配置文件用ACR冲洗不行，会加载色调曲线，风格化LUT表。要用开源软件RawTherape来加载DCP配置文件，只加载校色的Base table。<a href="https://pan.baidu.com/s/1zSW2UQ2NfF16cG7zuKrDvg?pwd=bxzz" target="_blank" rel="noreferrer">网盘</a>/0-软件/相机冲洗软件/里有。</p><p>把DCP配置文件和镜头矫正文件复制出来，优选Adobe Standard文件夹下由Adobe制作的DCP配置文件。</p><ul><li>Adobe Standard文件夹下即ACR中出现的Adobe标准Adobe颜色之类</li><li>Camera文件夹下即ACR中的相机匹配，据Adobe介绍，贴近相机jpg直出。</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>DCP配置文件：</span></span>
<span class="line"><span>C:\\ProgramData\\Adobe\\CameraRaw\\CameraProfiles</span></span>
<span class="line"><span>镜头矫正Lcp文件：</span></span>
<span class="line"><span>C:\\ProgramData\\Adobe\\CameraRaw\\LensProfiles</span></span>
<span class="line"><span></span></span>
<span class="line"><span>放自己捣鼓的配置文件给Adobe软件用：</span></span>
<span class="line"><span>%APPDATA%\\Adobe\\CameraRaw\\CameraProfiles</span></span>
<span class="line"><span>%APPDATA%\\Adobe\\CameraRaw\\LensProfiles</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Lightroom放在安装目录下：</span></span>
<span class="line"><span>C:\\Program Files\\Adobe\\Adobe Lightroom Classic\\Resources</span></span></code></pre></div><p>RawTherape软件-色彩（ALT+C）-ICM-输入配置（自定义）选中拷出来的自己机型的DCP配置文件，只启用Base table，不启用Look table和DCP色调曲线。</p><p>当前配置设置为ProPhoto，输出配置也设置为ProPhoto，渲染意图，绝对比色。</p><p><strong>可选</strong>加载镜头校准Lcp文件，变换（ALT+T）-镜头/几何-镜头矫正档案-LCP文件。<a href="https://helpx.adobe.com/camera-raw/digital-negative.html#Adobe_Lens_Profile_Creator" target="_blank" rel="noreferrer">DIY Adobe LCP</a></p><p>保存按钮是不算侧边栏最左边的按钮（CTRL+S），保存为TIFF-16bit，勾选BigTIFF（no metadata support），保存即可。这个软件的GUI跟后台程序之间可能有不一致的现象，保存后检查下内嵌的ICC是不是ProPhoto，该软件偶尔会莫名其妙转换成sRGB。</p><p>RawTherape软件在色靶图和白场图里挑一个比较亮的地方，对比两边的Lab的L值，色靶图L÷白场图L，+-两个图片的曝光设置控制在0.92左右。</p><p>之后在PS中打开色靶，白场图层高于原图，白场图层混合模式用划分，再存储副本保存为TIF。 <strong>如果没有俯拍架，</strong>数码冲洗后用PS透视裁切对齐客串白场的白纸。 白场校正后，检查纸白均匀度，如果出现纸白是（RGB，255，255，255）是不行的，要调整曝光。</p><p>校色的其他操作参考<a href="https://www.bilibili.com/video/BV1gFSCYqE5w" target="_blank" rel="noreferrer">无色卡-扫描仪校色打印机视频</a>，保存的tif重命名为dyj-pro.tif，跳过转换直接运行识别。</p><p>蹭DCP配置文件做出来校色文件色数会比较少，不过无所谓，颜色间相对联系是准的就行了。</p><p>用于无色卡校色打印机，实测可行：小米12S、尼康Z62。</p><p><strong>其他尝试，意义不大</strong>：</p><p>尼康Z62实测Camera文件夹下配置文件，在RawTherape中加载可能酌情全部启用，Look table、DCP色调曲线、Baseline exposure，具体自行测试。优选Flat字样配置文件（ACR中叫展平）。</p><p>如果用ACR冲洗，平场校正后的亮度均匀度会差一点，也可以。可能考虑Adobe标准或Adobe非彩色，这个非彩色应该是nertual，而不是意义不明的“非彩色”。</p><p>方法并不绝对，仅抛砖引玉。自行测试，主观评判效果，或上<a href="https://www.dpreview.com/reviews/image-comparison" target="_blank" rel="noreferrer">DPREVIEW网站</a>，下载需要的机型的RAW原图，冲洗后对比爱色丽24色卡的色值，看哪个配置文件色准相对更高。</p><h3 id="jpg直出变通方法" tabindex="-1">JPG直出变通方法 <a class="header-anchor" href="#jpg直出变通方法" aria-label="Permalink to “JPG直出变通方法”">​</a></h3><p>由于各家的jpg直出基本都是严重的风格化偏色，正常流程通常不具有实用性。变通方法，色靶不用色靶打印工具打印，当成一个具体的实际照片打印。不生成ICC，用脚本生成LUT。生成的LUT只适用于同一台相机拍的直出照片。</p><p><strong>原理</strong></p><p>以sRGB（127,127,127）色块为例，相机拍打印的sRGB（127,127,127）色块获得手机直出认为的rgb值。把相机认为的这个rgb值&gt;&gt;让打印机按sRGB（127,127,127）来打印就可以，以此类推，基于几百个色块建立LUT。</p><p><strong>操作</strong></p><p>色靶图片PS-编辑-指定配置文件，指定为sRGB。此处和手机相机设置的直出颜色配置保持一致，如果直出保存为displayP3，则指定为displayP3。</p><p>PS-打印，打印机管理色彩，打印机驱动设置色彩管理为无。</p><ul><li>拍JPG直出用的白场图可能可以用同款纸，普通纸还是同款纸自行测试。</li><li>直出尽量自动测光默认，不要加曝光，避免高光压缩导入误差。或自行测试。</li></ul><p>观察白场图和色靶图的亮度，要控制差不多位置的纸白的色靶图的亮度÷白场图，约为0.92左右。给白场图加一个调整图层-曝光，微调。</p><p>透视裁切到白场图的纸，白场图层高于色靶图层，白场图层混合模式，划分。</p><p>图像-模式-调整为16位，编辑-转换为配置文件-转换为ProPhoto。存储副本.tif后重命名为dyj-pro.tif拷到操作的色靶目录下，运行【31-识别】脚本。无色卡-扫描仪校色打印机脚本中【42-PRO-相机直出-生成LUT-sRGB.cmd】拷过来，双击运行生成LUT。</p><p>只能打印同一台相机jpg直出的照片，PS-调整-颜色查找-载入3D LUT，载入生成的LUT。PS-打印，打印机管理色彩，打印机驱动设置色彩管理为无。</p><h2 id="手机相机拍摄raw" tabindex="-1">手机相机拍摄RAW <a class="header-anchor" href="#手机相机拍摄raw" aria-label="Permalink to “手机相机拍摄RAW”">​</a></h2><p>优选国产手机，通常CMOS的底更大更好，iPhone更注重CMOS的视频性能。不过也无所谓，有啥用啥，都很随意。<strong>安卓自带相机应用找不到拍RAW的设置，考虑酷安下载MotionCam等软件。</strong></p><ul><li>小米自带相机，滑轮滑到专业模式，右上角JPG修改为RAW。</li></ul><p>徕卡标小米、哈苏标OPPO这种有ACR支持的手机相机拍的RAW，一般要自带相机拍的RAW，才能被ACR识别。如果用如MotionCam等软件拍的话，想被ACR识别，要仿照自带相机拍的RAW，修改Exif信息。不用ACR冲洗就无所谓了。</p><ul><li>iPhone pro机型<a href="https://support.apple.com/zh-cn/119916" target="_blank" rel="noreferrer">自带相机即可使用ProRAW格式拍摄。</a></li></ul><p>其他iPhone机型可使用:（注意确认软件的开发者，苹果商店李鬼不少）</p><ul><li>极影相机（Shenzhen Fotorgear Technology Co., Ltd）</li></ul><p>左上角JPG按钮，切换为Raw即可。</p><p>拍摄的DNG格式RAW文件选中或打开后，分享，比如分享给QQ发送给我的电脑。</p><ul><li>Lightroom(Adobe Inc.)</li></ul><p>需要登录Adobe账号，直接用APPLE ID登录即可。</p><p>启动后按右下角相机按钮切换到拍照模式，好像默认就是拍RAW，DNG。Lightroom在共享的时候，导出为原始格式或DNG即可。</p><h3 id="对焦位置" tabindex="-1">对焦位置 <a class="header-anchor" href="#对焦位置" aria-label="Permalink to “对焦位置”">​</a></h3><p>在翻拍时，观察离镜头最近的，既画面中间位置，然后利用棋盘格衡量画面各个位置相对镜头的距离，优先选择离镜头距离中等的位置作为自动对焦点。</p><h2 id="改善扫描图发白发灰发蒙发虚" tabindex="-1">改善扫描图发白发灰发蒙发虚 <a class="header-anchor" href="#改善扫描图发白发灰发蒙发虚" aria-label="Permalink to “改善扫描图发白发灰发蒙发虚”">​</a></h2><p>1、 调高饱和度。</p><p>2、找一处类似油墨的原稿中最黑的地方，扫描后，PS-调整-色阶图层，有3个滴管，最上面那个可以设置黑场，用那个滴管点一下最黑的地方，这个图层右上角的四条杠可以保存这个预设，然后应用到其他类似油墨的扫描图片上，这些图片的icc要尽量相同。或自行调高输入色阶。</p><p>3、如果觉得纸白不白，白场工具点纸白。</p><p>4、G7印刷标准的感知中性灰是Lab（59,0,-1）。对于印刷稿的扫描，调整-曲线图层，分别为RGB各曲线新建一个关键点，输入为Lab（59,0,-1）的RGB值，输出为Lab（54，0，0）的RGB值。通常sRGB的中性灰是20%灰，所以是Lab（54，0，0），对应（127,127,127）。即sRGB下，输入（141,142,144），输出（127,127,127）。<a href="https://www.bilibili.com/video/BV1ZJ4m1L7b9?t=1062.7" target="_blank" rel="noreferrer">参考视频</a>是打印的，输入输出的设置扫描和打印要反过来。</p><p>通常改善的是阴影灰蒙蒙发虚的情况。</p><p>PS录制动作新建色阶或曲线调整图层，应用保存的色阶或曲线设置，然后存储副本。之后在文件-自动-批处理即可批量应用。</p>`,132)]])}var s=t(a,[[`render`,o]]);export{i as __pageData,s as default};